function rateLimiter(fn, limit, interval) {
  const queue = [];
  let count = 0;

  function execute() {
    if (queue.length === 0) return;
    if (count < limit) {
      count++;
      const { resolve, args } = queue.shift();
      resolve(fn(...args));
      setTimeout(() => { count--; execute(); }, interval);
    }
  }

  return function(...args) {
    return new Promise(resolve => {
      queue.push({ resolve, args });
      execute();
    });
  };
}

class TaskScheduler {
  constructor() {
    this.queues = { high: [], medium: [], low: [] };
    this.running = false;
  }

  add(task, priority = 'medium') {
    this.queues[priority].push(task);
    if (!this.running) this.run();
  }

  async run() {
    this.running = true;
    while (this.queues.high.length || this.queues.medium.length || this.queues.low.length) {
      const task = this.queues.high.shift() || this.queues.medium.shift() || this.queues.low.shift();
      if (task) await task();
    }
    this.running = false;
  }
}

async function promisePool(tasks, concurrency) {
  const results = [];
  let index = 0;

  async function worker() {
    while (index < tasks.length) {
      const i = index++;
      results[i] = await tasks[i]();
    }
  }

  const workers = Array.from({ length: Math.min(concurrency, tasks.length) }, () => worker());
  await Promise.all(workers);
  return results;
}

function diff(oldNode, newNode) {
  const patches = [];
  if (!oldNode) {
    patches.push({ type: 'CREATE', node: newNode });
  } else if (!newNode) {
    patches.push({ type: 'REMOVE' });
  } else if (typeof oldNode !== typeof newNode || 
             (typeof oldNode === 'string' && oldNode !== newNode) ||
             oldNode.tag !== newNode.tag) {
    patches.push({ type: 'REPLACE', node: newNode });
  } else if (newNode.tag) {
    const propPatches = diffProps(oldNode.props, newNode.props);
    if (propPatches.length) patches.push({ type: 'PROPS', props: propPatches });
    const maxLen = Math.max(oldNode.children?.length || 0, newNode.children?.length || 0);
    for (let i = 0; i < maxLen; i++) {
      const childPatches = diff(oldNode.children?.[i], newNode.children?.[i]);
      if (childPatches.length) patches.push({ type: 'CHILD', index: i, patches: childPatches });
    }
  }
  return patches;
}

function diffProps(oldProps = {}, newProps = {}) {
  const patches = [];
  for (const key in { ...oldProps, ...newProps }) {
    if (oldProps[key] !== newProps[key]) patches.push({ key, value: newProps[key] });
  }
  return patches;
}

class Container {
  constructor() {
    this.services = new Map();
    this.singletons = new Map();
  }

  register(name, factory, singleton = false) {
    this.services.set(name, { factory, singleton });
  }

  resolve(name) {
    const service = this.services.get(name);
    if (!service) throw new Error(`Service ${name} not registered`);
    if (service.singleton) {
      if (!this.singletons.has(name)) {
        this.singletons.set(name, service.factory(this));
      }
      return this.singletons.get(name);
    }
    return service.factory(this);
  }
}

function delegate(parent, eventType, selector, handler) {
  parent.addEventListener(eventType, (event) => {
    let target = event.target;
    while (target && target !== parent) {
      if (target.matches(selector)) {
        handler.call(target, event);
        return;
      }
      target = target.parentElement;
    }
  });
}

